using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents still use "Discriminator", so pin the old name.
            entity.HasDiscriminator().HasJsonPropertyName("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents use "Blog|<key>", so preserve the old format.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 3: Cosmos DB does not support indexes defined via EF.
            // HasIndex() now throws at model validation in EF 9; removed.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }

    // Breaking change 4: EF 9 sync I/O over async now throws by default.
    // See SyncJob.cs for the fix (switch to async APIs).
}

